class Solution {
public:
    vector<int> maxDepthAfterSplit(string seq) {
        vector<int> result(seq.length(), 0);
        int left = 0, right = 0;
        for (int i = 0; i < seq.length(); i++) {
            if (seq[i] == '(') {
                result[i] = left;
                left++;
            } else if (seq[i] == ')') {
                result[i] = right;
                right++;
            } else {
                result[i] = max(result[left], result[right]);
                left++;
                right--;
            }
        }
    }
};
```

